  ('optician-moex-01935', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者為正視眼，以推進法測量其調節幅度（amplitude of accommodation）為8 D，其調節近點（near point of accommodation）為下列何者？', '["6.5 cm", "8.5 cm", "10.5 cm", "12.5 cm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b5729e769b59", "answer_pdf_sha1": "e88e08bae45b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
